export type AbcClass = 'A' | 'B' | 'C';

export interface AbcItem {
  abc: AbcClass;
  [key: string]: unknown;
}

/** ABC-классификация: A ≤80%, B ≤95%, C >95% кумулятивной доли. */
export function computeAbcClasses<T extends object>(
  items: T[],
  axis: keyof T,
): (T & { abc: AbcClass })[] {
  const sorted = [...items].sort((a, b) => (b[axis] as number) - (a[axis] as number));
  const total = sorted.reduce((sum, item) => sum + (item[axis] as number), 0);
  if (total === 0) {
    return sorted.map((item) => ({ ...item, abc: 'C' as AbcClass }));
  }

  let cum = 0;
  return sorted.map((item) => {
    cum += item[axis] as number;
    const share = cum / total;
    const abc: AbcClass = share <= 0.8 ? 'A' : share <= 0.95 ? 'B' : 'C';
    return { ...item, abc };
  });
}

import { InjectionToken } from '@angular/core';
import { environment } from '../../../environments/environment';

export interface ApiConfig {
  apiBase: string;
}

export const API_CONFIG = new InjectionToken<ApiConfig>('API_CONFIG', {
  providedIn: 'root',
  factory: () => ({
    apiBase: environment.apiBase,
  }),
});

import type { CategoryKey, DetailPopover, LflMetric, PeriodInfo } from './common.model';

export interface KpiBlock {
  value: number;
  lfl?: LflMetric | null;
  forecast: {
    value: number;
    planPct: number;
    trackPct: number;
    risk: boolean;
    headline?: string;
  };
}

export interface RevenueKpi extends KpiBlock {
  checks: number;
  guests: number;
}

export interface AvgCheckKpi extends KpiBlock {
  perGuest: number;
  qualityFlag: boolean;
}

export interface GuestsKpi extends KpiBlock {
  perCheck: number;
  checks: number;
}

export interface RevenueDay {
  day: number;
  weekday: number;
  revenue: number;
  plan: number;
  checks: number;
  guests: number;
  avg: number;
}

export interface DashboardData {
  greeting: string;
  period: PeriodInfo;
  kpis: {
    revenue: RevenueKpi;
    avgCheck: AvgCheckKpi;
    guests: GuestsKpi;
  };
  revenueByDay: RevenueDay[];
  revenueByDayMax: number;
  reviews: {
    score: number;
    count: number;
    split: {
      good: number;
      mid: number;
      bad: number;
      goodPct: number;
      midPct: number;
      badPct: number;
    };
    sources: { name: string; score: number; count: number }[];
  } | null;
  foodcostMini: {
    caption: string;
    items: {
      key: CategoryKey;
      name: string;
      pct: number;
      goal: number;
      deltaPP: number;
      dir: LflMetric['dir'];
    }[];
  };
  categories: { key: CategoryKey; name: string; pct: number }[];
  stock: {
    total: number;
    items: { key: CategoryKey; name: string; value: number }[];
  } | null;
  details: Record<string, DetailPopover>;
}

