.kpop {
  position: fixed;
  z-index: 60;
  width: 272px;
  opacity: 0;
  pointer-events: none;
  background: var(--popover-bg);
  border: 1px solid rgba(110, 107, 255, 0.45);
  border-radius: 14px;
  padding: 14px 16px 13px;
  box-shadow: var(--popover-shadow);
  transform: translateY(6px);
  transition:
    opacity 0.15s,
    transform 0.15s;

  &.show {
    opacity: 1;
    pointer-events: auto;
    transform: none;
  }

  &::before {
    content: '';
    position: absolute;
    top: -6px;
    left: var(--ax, 28px);
    width: 10px;
    height: 10px;
    background: var(--popover-bg);
    border-left: 1px solid rgba(110, 107, 255, 0.45);
    border-top: 1px solid rgba(110, 107, 255, 0.45);
    transform: rotate(45deg);
  }

  &.day::before {
    top: auto;
    bottom: -6px;
    border: 0;
    border-right: 1px solid rgba(110, 107, 255, 0.45);
    border-bottom: 1px solid rgba(110, 107, 255, 0.45);
  }

