              font-family="Manrope"
            >
              {{ bar.label }}
            </text>
          }

          @if (selectedIndex() !== null) {
            @let sel = layout().bars[selectedIndex()!];
            <rect
              [attr.x]="sel.x"
              [attr.y]="sel.y"
              [attr.width]="sel.w"
