          >
            {{ line.label }}
          </text>
        }

        <polygon [attr.points]="chart().areaPoints" fill="url(#stockArea)" />
        <polyline
          [attr.points]="chart().polylinePoints"
          fill="none"
          [attr.stroke]="chart().color"
          stroke-width="2.5"
        />

        @for (dot of chart().dots; track $index) {
          <circle
            [attr.cx]="dot.cx"
            [attr.cy]="dot.cy"
            r="3.5"
            fill="#0D1220"
            [attr.stroke]="chart().color"
